import{_ as t,o as s,c as r,a2 as a}from"./chunks/framework.Cuq8tsM6.js";const m=JSON.parse('{"title":"Guide de Publication","description":"","frontmatter":{"title":"Guide de Publication"},"headers":[],"relativePath":"docs/fr/publishers/sponsored-social/guide.md","filePath":"docs/fr/publishers/sponsored-social/guide.md"}'),o={name:"docs/fr/publishers/sponsored-social/guide.md"};function i(n,e,d,l,u,p){return s(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="guide-de-publication-tagging" tabindex="-1">Guide de Publication &amp; Tagging <a class="header-anchor" href="#guide-de-publication-tagging" aria-label="Permalink to &quot;Guide de Publication &amp; Tagging&quot;">​</a></h1><p>Pour que l&#39;Annonceur puisse payer la diffusion, vous devez impérativement activer les options de partenariat lors de la publication.</p><hr class="my-6"><h2 class="text-purple-200 mb-4">Sur Instagram (Partnership Ads)</h2><div style="border-left:4px solid #d62976;padding-left:20px;"><div style="margin-bottom:20px;"><h3 class="mt-0 fs-4">1. Préparez le post</h3><p class="mb-0">Créez votre Post ou Reel normalement. Arrivez à l&#39;étape finale (juste avant de cliquer sur &quot;Partager&quot;).</p></div><div style="margin-bottom:20px;"><h3 class="mt-0 fs-4">2. Paramètres Avancés</h3><p class="mb-0">Descendez tout en bas et cliquez sur <strong>&quot;Paramètres avancés&quot;</strong>.</p></div><div style="margin-bottom:20px;"><h3 class="mt-0 fs-4">3. Ajouter le label</h3><p class="mb-0">Activez l&#39;option <strong>&quot;Ajouter un label Partenariat rémunéré&quot;</strong>.</p></div><div style="margin-bottom:20px;"><h3 class="mt-0 fs-4">4. Identifier la marque</h3><p class="mb-0">Cliquez sur <strong>&quot;Ajouter des partenaires de marque&quot;</strong> et recherchez le nom du compte de l&#39;Annonceur (indiqué dans le brief).</p></div><div style="background-color:#fff0f3;border:1px dashed #d62976;padding:15px;border-radius:8px;"><h3 class="mt-0 text-red-200 fs-4">⚠️ ÉTAPE CRITIQUE</h3><p class="mb-0">Vous devez absolument activer l&#39;option :<br><strong>&quot;Autoriser le partenaire de marque à booster&quot;</strong> (Allow brand partner to boost).</p><p class="fs-2 mt-2 mb-0 text-grey-dk-000"><em>Sans cette case cochée, nous ne pouvons pas lancer la campagne média et votre rémunération peut être bloquée.</em></p></div></div><hr class="my-6"><h2 class="text-purple-200 mb-4">Sur TikTok (Spark Ads)</h2><div style="border-left:4px solid #000;padding-left:20px;"><div style="margin-bottom:20px;"><h3 class="mt-0 fs-4">1. Paramètres de publicité</h3><p class="mb-0">Publiez la vidéo. Allez dessus, cliquez sur les <strong>3 points (...)</strong> en bas à droite, puis faites défiler jusqu&#39;à <strong>&quot;Paramètres de publicité&quot;</strong> (Ad settings).</p></div><div style="margin-bottom:20px;"><h3 class="mt-0 fs-4">2. Autorisation</h3><p class="mb-0">Activez l&#39;option <strong>&quot;Autorisation de publicité&quot;</strong> (Ad authorization).</p></div><div style="margin-bottom:20px;"><h3 class="mt-0 fs-4">3. Générer le code</h3><p class="mb-0">Cliquez sur <strong>&quot;Générer un code&quot;</strong>, choisissez une durée (30 ou 60 jours) et copiez le code.</p></div><div style="background-color:#f6f8fa;border:1px solid #e1e4e8;padding:15px;border-radius:8px;"><strong>📨 Action finale :</strong><br> Collez ce code dans la messagerie de la campagne sur <a href="https://app.getinside.media/">app.getinside.media</a> pour que l&#39;annonceur puisse lier la vidéo. </div></div><hr class="my-6"><h2 class="text-grey-dk-000 mb-4">Bonnes Pratiques Éditoriales</h2><div style="display:grid;grid-template-columns:repeat(auto-fit, minmax(250px, 1fr));gap:20px;"><div style="border:1px solid #e1e4e8;border-radius:8px;padding:20px;"><strong>Authenticité</strong><p class="fs-2 text-grey-dk-000 mb-0">Utilisez votre ton habituel. Ne jouez pas un rôle, c&#39;est ce que l&#39;Annonceur recherche.</p></div><div style="border:1px solid #e1e4e8;border-radius:8px;padding:20px;"><strong>Transparence</strong><p class="fs-2 text-grey-dk-000 mb-0">L&#39;outil de partenariat ajoute automatiquement la mention &quot;Partenariat rémunéré&quot;, ce qui vous met en conformité avec la réglementation française sur la publicité.</p></div><div style="border:1px solid #e1e4e8;border-radius:8px;padding:20px;"><strong>Performance</strong><p class="fs-2 text-grey-dk-000 mb-0">Partagez le lien de votre publication avec votre gestionnaire de campagne getinside pour le suivi des performances.</p></div></div>',11)])])}const g=t(o,[["render",i]]);export{m as __pageData,g as default};
